import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface RecentGrade {
  subject: string;
  grade: string;
}

interface SubjectPerformance {
  subject: string;
  score: number;
}

interface WidgetData {
  currentGPA: number;
  recentGrades: RecentGrade[];
  subjectPerformance: SubjectPerformance[];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const themeColor = response.meta.primaryColor;
  const accentColor = response.meta.accentColor;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 480, bgcolor: '#2C3E50' }} elevation={3}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: themeColor }}>
              Current GPA
            </Typography>
            <Typography variant="h3" fontWeight={700} sx={{ color: '#ECF0F1' }}>
              {widgetData.currentGPA.toFixed(2)}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#BDC3C7' }}>
              Recent Grades
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {widgetData.recentGrades.map((grade) => (
                <Chip
                  key={grade.subject}
                  label={`${grade.subject}: ${grade.grade}`}
                  sx={{ fontSize: '11px', bgcolor: accentColor, color: '#2C3E50' }}
                />
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 180 }}>
            <BarChart
              height={180}
              series={[
                {
                  data: widgetData.subjectPerformance.map((performance) => performance.score),
                  color: accentColor,
                },
              ]}
              xAxis={[
                {
                  data: widgetData.subjectPerformance.map((performance) => performance.subject),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 10,
                    fill: '#ECF0F1',
                  },
                },
              ]}
              yAxis={[
                {
                  scaleType: 'linear',
                  tickLabelStyle: {
                    fontSize: 10,
                    fill: '#ECF0F1',
                  },
                },
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
